customCSS:
/* Theme Modal */
.modal { background: rgba(10,0,12,0.82) !important; backdrop-filter: blur(7px) saturate(130%) !important; -webkit-backdrop-filter: blur(7px) saturate(130%) !important; }
.modal-content { background: radial-gradient(circle at 20% 0%, rgba(75,0,130,0.82), rgba(25,0,25,0.98) 48%, rgba(12,0,16,0.98)) !important; border: 1px solid rgba(220,20,60,0.72) !important; border-radius: 6px !important; box-shadow: 0 0 28px rgba(220,20,60,0.32), 0 24px 52px rgba(0,0,0,0.72), inset 0 1px 0 rgba(220,20,60,0.22) !important; color: #e6e6fa !important; }
.modal-title, .settings-title, .modal-content h4 { color: #ff6b86 !important; text-shadow: 0 0 10px rgba(220,20,60,0.7) !important; }
.app-dialog-message, .trigger-description, .community-template .description { color: #f0e6ff !important; }
.import-hint, .settings-help, .hotkey-help, .range-labels, .community-template .task-count { color: #dda0dd !important; }
.community-template { background: rgba(25,0,25,0.58) !important; border: 1px solid rgba(139,0,0,0.42) !important; }
.modal-btn.primary { background: linear-gradient(180deg, rgba(139,0,0,0.86), rgba(75,0,130,0.86)) !important; border: 1px solid rgba(220,20,60,0.75) !important; color: #ffe6ef !important; }
.modal-btn.secondary { background: rgba(35,0,35,0.82) !important; border: 1px solid rgba(75,0,130,0.8) !important; color: #dda0dd !important; }
.modal-btn:hover { box-shadow: 0 0 14px rgba(220,20,60,0.45) !important; }
.modal-content-dialog.app-dialog-tone-danger { border-color: #ff1744 !important; }
.modal-content-dialog.app-dialog-tone-danger .modal-title { color: #ff8ba0 !important; }
